index 04ea12ef0f12..ed48d5db98e2 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -963,6 +963,11 @@ bool VectorCombine::scalarizeBinopOrCmp(Instruction &I) {
   uint64_t Index = IsConst0 ? Index1 : Index0;
   Type *ScalarTy = IsConst0 ? V1->getType() : V0->getType();
   Type *VecTy = I.getType();
+
+  // Ignore bogus insert/extract index for fixed vectors.
+  if (auto *FixedVecTy = dyn_cast<FixedVectorType>(VecTy))
+    if (Index >= FixedVecTy->getNumElements())
+      return false;
   assert(VecTy->isVectorTy() &&
          (IsConst0 || IsConst1 || V0->getType() == V1->getType()) &&
          (ScalarTy->isIntegerTy() || ScalarTy->isFloatingPointTy() ||

